SELECT m.*
FROM models AS m
JOIN users AS u ON m.created_by = u.user_id
WHERE u.user_id = (
    SELECT MIN(user_id) FROM users
);

SELECT COUNT(model_id)
FROM dataset_usage
WHERE dataset_id = 0;

SELECT evaluation_id, score
FROM model_evaluations
ORDER BY evaluation_id ASC;

SELECT e.evaluation_id, e.score
FROM model_evaluations e
WHERE e.score > (SELECT AVG(score) FROM model_evaluations);

SELECT m.model_name, m.num_test 
FROM models AS m
WHERE m.num_test = (SELECT MAX(num_test) FROM models);
